Func<string, Tekla.Structures.Model.Beam> resolveBeam = guid => {
    var id = new Tekla.Structures.Identifier(new System.Guid(guid));
    return (Tekla.Structures.Model.Beam)model.SelectModelObject(id);
};

Func<Tekla.Structures.Model.Beam, Tekla.Structures.Model.Beam, Tekla.Structures.Model.Component> makeConn = (primary, secondary) => {
    var input = new Tekla.Structures.Model.ComponentInput();
    input.AddInputObject(primary);
    input.AddInputObject(secondary);
    var comp = new Tekla.Structures.Model.Component(input);
    comp.Number = 146;
    comp.Name = "Two-sided clip angle 146";
    return comp;
};

